public class Currency {
    public static void main(String[] args) {
        System.out.println(format(1500.0));
        System.out.println(format(1500.0, "$"));
        System.out.println(format(1500.0, "€", false));
    }

    public static String format(double amount) {
        return "₹" + amount;
    }

    public static String format(double amount, String symbol) {
        return symbol + amount;
    }

    public static String format(double amount, String symbol, boolean showDecimal) {
        if (showDecimal) {
            return symbol + amount;
        }
        return symbol + (int) amount;
    }
}

public class ShapeCalculator {
    public static void main(String[] args) {
        double square = area(5.0);
        double rect = area(4.0, 6.0);
        double tri = area(3.0, 8.0, true);

        System.out.println("Square area: " + square);
        System.out.println("Rectangle area: " + rect);
        System.out.println("Triangle area: " + tri);

        double total = totalArea(square, rect, tri);
        System.out.println("Total area: " + total);
    }

    public static double area(double side) {
        return side * side;
    }

    public static double area(double width, double height) {
        return width * height;
    }

    public static double area(double base, double height, boolean isTriangle) {
        return 0.5 * base * height;
    }

    public static double totalArea(double... areas) {
        double total = 0;
        for (double a : areas) {
            total += a;
        }
        return total;
    }
}
